import Foundation

class ImagePickerTestImages: NSObject {
    @objc static var jpgTestData: Data {
        let bundle = Bundle(for: self)
        if let url = bundle.url(forResource: "jpgImage", withExtension: "jpg"),
           let data = try? Data(contentsOf: url)
        {
            return data
        }
        return Data(base64Encoded: "") ?? Data()
    }

    @objc static var jpgTallTestData: Data {
        let bundle = Bundle(for: self)
        if let url = bundle.url(forResource: "jpgImageTall", withExtension: "jpg"),
           let data = try? Data(contentsOf: url)
        {
            return data
        }
        return Data(base64Encoded: "") ?? Data()
    }

    @objc static var pngTestData: Data {
        let bundle = Bundle(for: self)
        if let url = bundle.url(forResource: "pngImage", withExtension: "png"),
           let data = try? Data(contentsOf: url)
        {
            return data
        }
        return Data(base64Encoded: "") ?? Data()
    }

    @objc static var gifTestData: Data {
        let bundle = Bundle(for: self)
        if let url = bundle.url(forResource: "gifImage", withExtension: "gif"),
           let data = try? Data(contentsOf: url)
        {
            return data
        }
        return Data(base64Encoded: "") ?? Data()
    }
}
